def pad_body(body: str, paragraphs: list[str], target: int = 4500) -> str:
    import re

    def wc(s: str) -> int:
        t = re.sub(r"<[^>]+>", " ", s)
        return len(re.sub(r"\s+", " ", t).split())

    out = body
    i = 0
    while wc(out) < target and i < len(paragraphs):
        out += "\n\n" + paragraphs[i]
        i += 1
    return out